// createBookmarkViaAPI seeds fixture data through the real Create
// endpoint, not by touching the fake directly — mirrors #3's black-box
// discipline (see TestCreateBookmark_RetrievableViaBoardImmediatelyAfter).
func createBookmarkViaAPI(t *testing.T, srv *httptest.Server, url string) domain.Bookmark {
	t.Helper()
	resp, err := http.Post(srv.URL+"/api/bookmarks", "application/json", strings.NewReader(`{"url": "`+url+`"}`))
	require.NoError(t, err)
	require.Equal(t, http.StatusCreated, resp.StatusCode)
	var b domain.Bookmark
	decodeJSON(t, resp, &b)
	return b
}

// moveBookmark POSTs to /api/bookmarks/{id}/move. id is a plain string,
// not domain.BookmarkID, so malformed-id tests can pass arbitrary values.
func moveBookmark(t *testing.T, srv *httptest.Server, id, body string) *http.Response {
	t.Helper()
	resp, err := http.Post(srv.URL+"/api/bookmarks/"+id+"/move", "application/json", strings.NewReader(body))
	require.NoError(t, err)
	return resp
}

