// from interview: Q2/Q3 — omitted keys (the natural REST-client shape,
// not explicit null) must behave identically to null: no neighbor
// constraint, end-of-column.
func TestMoveBookmark_NoBeforeAfterKeys_EndOfColumn(t *testing.T) {
	srv, _ := newTestServer(t)
	first := createBookmarkViaAPI(t, srv, "https://example.com/1")
	second := createBookmarkViaAPI(t, srv, "https://example.com/2")

	resp1 := moveBookmark(t, srv, string(first.ID), `{"target_status": "reading"}`)
	require.Equal(t, http.StatusOK, resp1.StatusCode)
	resp2 := moveBookmark(t, srv, string(second.ID), `{"target_status": "reading"}`)
	require.Equal(t, http.StatusOK, resp2.StatusCode)

	boardResp, err := http.Get(srv.URL + "/api/board")
	require.NoError(t, err)
	var board domain.Board
	decodeJSON(t, boardResp, &board)
	require.Len(t, board.Reading, 2)
	assert.Equal(t, first.ID, board.Reading[0].ID, "first move (before/after omitted) lands at end-of-column")
	assert.Equal(t, second.ID, board.Reading[1].ID, "second move also lands at end, after the first")
}

// from interview: Q2 — a real, valid neighbor is honored: Before wins,
// the moved card lands immediately before it (ports.go's locked Move
// contract, exercised end-to-end through the handler).
func TestMoveBookmark_ValidBeforeNeighbor_PlacedBeforeIt(t *testing.T) {
	srv, _ := newTestServer(t)
	anchor := createBookmarkViaAPI(t, srv, "https://example.com/anchor")
	moving := createBookmarkViaAPI(t, srv, "https://example.com/moving")

	anchorResp := moveBookmark(t, srv, string(anchor.ID), `{"target_status": "reading"}`)
	require.Equal(t, http.StatusOK, anchorResp.StatusCode)

	resp := moveBookmark(t, srv, string(moving.ID), `{"target_status": "reading", "before": "`+string(anchor.ID)+`"}`)
	require.Equal(t, http.StatusOK, resp.StatusCode)

	boardResp, err := http.Get(srv.URL + "/api/board")
	require.NoError(t, err)
	var board domain.Board
	decodeJSON(t, boardResp, &board)
	require.Len(t, board.Reading, 2)
	assert.Equal(t, moving.ID, board.Reading[0].ID, "moving must land immediately before the anchor")
	assert.Equal(t, anchor.ID, board.Reading[1].ID)
}

// from interview: Q2 — the core locked decision: a well-formed but
// nonexistent neighbor id is NOT a 400. It's opaque to the API layer for
// existence purposes and delegated straight to Move's fallback.
func TestMoveBookmark_WellFormedNonexistentNeighbor_FallsBackEndOfColumn_Returns200(t *testing.T) {
	srv, _ := newTestServer(t)
	existing := createBookmarkViaAPI(t, srv, "https://example.com/existing")
	moving := createBookmarkViaAPI(t, srv, "https://example.com/moving")

	existingResp := moveBookmark(t, srv, string(existing.ID), `{"target_status": "reading"}`)
	require.Equal(t, http.StatusOK, existingResp.StatusCode)

	const wellFormedNonexistent = "99999999-9999-9999-9999-999999999999"
	resp := moveBookmark(t, srv, string(moving.ID), `{"target_status": "reading", "before": "`+wellFormedNonexistent+`"}`)
	assertJSONContentType(t, resp)
	assert.Equal(t, http.StatusOK, resp.StatusCode, "a well-formed but nonexistent neighbor id must NOT be a 400 — opaque to the API layer, delegated to Move's fallback")

	boardResp, err := http.Get(srv.URL + "/api/board")
	require.NoError(t, err)
	var board domain.Board
	decodeJSON(t, boardResp, &board)
	require.Len(t, board.Reading, 2)
	assert.Equal(t, existing.ID, board.Reading[0].ID)
	assert.Equal(t, moving.ID, board.Reading[1].ID, "falls back to end-of-column")
}

