// --- Redaction scar (interview Q7 — the #2/#3 precedent) ------------------
//
// These two use httptest.NewRecorder() + router.ServeHTTP directly,
// deliberately bypassing the live server — see setup_test.go's
// methodology note (a client-canceled context aborts the request before
// the server-side handler runs, making checkContext's server-side path
// un-exercisable through a live round-trip).

// from interview: Q7 — the 500 fallthrough must be the exact constant
// envelope, never the wrapped Move error (which could carry pg text, a
// 22P02-echoed bad value, etc.).
func TestMoveBookmark_ContextCanceled_Returns500Internal_GenericMessage(t *testing.T) {
	repo := newFakeRepoForRecorder(t)
	router := api.NewRouter(repo)

	created, err := repo.Create(context.Background(), domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)

	ctx, cancel := context.WithCancel(context.Background())
	cancel()
	req := httptest.NewRequest(http.MethodPost, "/api/bookmarks/"+string(created.ID)+"/move", strings.NewReader(`{"target_status": "reading"}`))
	req = req.WithContext(ctx)
	rec := httptest.NewRecorder()

	router.ServeHTTP(rec, req)

	assert.Equal(t, http.StatusInternalServerError, rec.Code)
	assert.Equal(t, "application/json", rec.Header().Get("Content-Type"))
	var body errorEnvelope
	require.NoError(t, decodeRecorderJSON(rec, &body))
	assert.Equal(t, "internal", body.Error)
	assert.Equal(t, "internal server error", body.Message, "must be the constant generic message, never the wrapped Move error")
}

